public class SwitchBreak {
    public static void main(String[] args) {
        int day = 2;
        String name = switch (day) {
            case 1 -> "Monday";
            case 2 -> "Tuesday";
            default -> "Unknown";
        };
        System.out.println(name);
    }
}
